import android.app.Activity;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Bundle;
import android.util.Log;

import com.google.android.gms.location.Geofence;
import com.google.android.gms.location.GeofencingClient;
import com.google.android.gms.location.GeofencingRequest;
import com.google.android.gms.location.LocationServices;
import com.google.android.gms.tasks.OnAddGeofencesResult;
import com.google.android.gms.tasks.OnFailureResult;
import com.google.android.gms.tasks.OnSuccessListener;

public class GeofencingActivity extends Activity {
    private static final String TAG = "GeofencingActivity";
    private static final String GEOFENCE_ID = "my_geofence";
    private static final int GEOFENCE_RADIUS = 100; // meters
    private static final int GEOFENCE_EXPIRATION = 60 * 60 * 1000; // 1 hour

    private GeofencingClient mGeofencingClient;
    private PendingIntent mGeofencePendingIntent;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        mGeofencingClient = LocationServices.getGeofencingClient(this);
        mGeofencePendingIntent = PendingIntent.getService(this, 0, new Intent(this, GeofenceService.class), PendingIntent.FLAG_UPDATE_CURRENT);
    }

    public void addGeofence() {
        Geofence geofence = new Geofence.Builder()
                .setRequestId(GEOFENCE_ID)
                .setCircularRegion(37.7749, -122.4194, GEOFENCE_RADIUS)
                .setExpirationDuration(GEOFENCE_EXPIRATION)
                .setTransitionTypes(Geofence.GEOFENCE_TRANSITION_ENTER | Geofence.GEOFENCE_TRANSITION_EXIT)
                .build();

        GeofencingRequest request = new GeofencingRequest.Builder()
                .addGeofence(geofence)
                .build();

        mGeofencingClient.addGeofences(request, mGeofencePendingIntent)
                .addOnSuccessListener(this, new OnSuccessListener<Void>() {
                    @Override
                    public void onSuccess(Void aVoid) {
                        Log.d(TAG, "Geofence added");
                    }
                })
                .addOnFailureResult(this, new OnFailureResult<Void>() {
                    @Override
                    public void onFailureResult(Void aVoid) {
                        Log.e(TAG, "Failed to add geofence");
                    }
                });
    }
}
```
